css:
.vbes-team-member {
  max-width: 320px;
  margin: 0 auto;
  text-align: center;
  padding: 32px 24px;
}
.vbes-team-member__photo-wrap {
  width: 140px;
  height: 140px;
  margin: 0 auto 20px;
  border-radius: 50%;
  overflow: hidden;
  border: 4px solid {{accent_color}};
}
.vbes-team-member__photo {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}
.vbes-team-member__name {
  font-size: 1.25rem;
  font-weight: 700;
  margin: 0 0 4px;
  color: #1a1a1a;
}
.vbes-team-member__role {
  font-size: 0.9rem;
  color: {{accent_color}};
  font-weight: 600;
  margin: 0 0 16px;
}
.vbes-team-member__bio {
  font-size: 0.9rem;
  line-height: 1.6;
  color: #555;
  margin: 0;
}
